Here's a simple Discord bot using Discord.js v14 with a slash command for banning members. Make sure you have node.js installed on your system.

1. Create a new directory for your project and navigate to it:

```bash
mkdir discord-bot && cd discord-bot
```

2. Initialize a new Node.js project:

```bash
npm init -y
```

3. Install the required packages:

```bash
npm install discord.js
npm install dotenv
```

4. Create a `.env` file in the project directory and add your Discord bot token:

```bash
touch .env
```

```env
DISCORD_BOT_TOKEN=your_bot_token_here
```

Replace `your_bot_token_here` with your Discord bot token.

5. Create a `bot.js` file in the project directory and paste the following code:

```javascript
const { Client, Collection, Intents } = require('discord.js');
const { SlashCommandBuilder } = require('@discordjs/builders');
const { readdirSync } = require('fs');

const client = new Client({ intents: [Intents.FLAGS.GUILD_MESSAGES] });

client.commands = new Collection();

const commandsPath = './commands';
const commandFiles = readdirSync(commandsPath).filter(file => file.endsWith('.js'));

for (const file of commandFiles) {
  const command = require(`${commandsPath}/${file}`);
  client.commands.set(command.data.name, command);
}

client.on('ready', () => {
  console.log(`Logged in as ${client.user.tag}!`);
});

client.on('interactionCreate', async interaction => {
  if (!interaction.isChatInputCommand()) return;

  const command = interaction.client.commands.get(interaction.commandName);

  if (!command) {
    console.error(`No command matching ${interaction.commandName} was found.`);
    return;
  }

  try {
    await command.execute(interaction);
  } catch (error) {
    console.error(error);
    await interaction.reply({ content: 'There was an error while executing this command!', ephemeral: true });
  }
});

const slashBanCommand = new SlashCommandBuilder()
  .setName('ban')
  .setDescription('Bans a user')
  .addUserOption(option =>
    option.setName('user').setDescription('The user to ban').setRequired(true)
  );

client.commands.set('ban', new BanCommand(slashBanCommand));

client.login(process.env.DISCORD_BOT_TOKEN);
```

6. Create a `commands` directory in the project directory and create a `ban.js` file inside the `commands` directory.

7. Paste the following content into the `ban.js` file:

```javascript
const { CommandInteraction } = require('discord.js');

module.exports = {
  data: slashBanCommand,
  async execute(interaction) {
    const user = interaction.options.getUser('user');

    await interaction.guild.members.ban(user.id, {
      reason: 'Banned by slash command'
    });

    await interaction.reply({ content: `${user.tag} has been banned!`, ephemeral: true });
  }
};
```

Now, start your Discord bot by running the following command:

```bash
node bot.js
```

Your Discord bot is now ready to use the ban command.

